  1	import React, { FC, MouseEvent } from 'react';
  2	
  3	import { TemplateParameter } from '@kubevirt-ui/kubevirt-api/console';
  4	import FormPFSelect from '@kubevirt-utils/components/FormPFSelect/FormPFSelect';
  5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  6	import { FormGroup, SelectOption, TextInput } from '@patternfly/react-core';
  7	
  8	import { PARAMETER_VALUE_TYPES } from './constants';
  9	import { getValueTypeFromParameter } from './utils';
 10	
 11	type ParameterValueEditorProps = {
 12	  isEditDisabled?: boolean;
 13	  onChange: (parameter: TemplateParameter) => void;
 14	  parameter: TemplateParameter;
 15	};
 16	
 17	const SelectParameterValueType: FC<ParameterValueEditorProps> = ({
 18	  isEditDisabled,
 19	  onChange,
 20	  parameter,
 21	}) => {
 22	  const { t } = useKubevirtTranslation();
 23	
 24	  const valueType = getValueTypeFromParameter(parameter);
 25	
 26	  const handleChange = (event: MouseEvent<HTMLSelectElement>, value: string) => {
 27	    const newParameter = { ...parameter };
 28	    switch (value) {
 29	      case PARAMETER_VALUE_TYPES.GENERATED:
 30	        delete newParameter.value;
 31	        onChange({ ...newParameter, generate: 'expression' });
 32	        break;
 33	      case PARAMETER_VALUE_TYPES.VALUE:
 34	        delete newParameter.generate;
 35	        delete newParameter.from;
 36	        onChange({ ...newParameter, value: '' });
 37	        break;
 38	      case PARAMETER_VALUE_TYPES.NONE:
 39	        delete newParameter.generate;
 40	        delete newParameter.from;
 41	        delete newParameter.value;
 42	        onChange(newParameter);
 43	        break;
 44	    }
 45	  };
 46	
 47	  return (
 48	    <>
 49	      <FormGroup fieldId={`${parameter.name}-value-type`} label={t('Default value type')}>
 50	        <FormPFSelect
 51	          onSelect={handleChange}
 52	          selected={valueType}
 53	          toggleProps={{ isDisabled: isEditDisabled }}
 54	        >
 55	          <SelectOption
 56	            description={t('Value generated using an expression')}
 57	            value={PARAMETER_VALUE_TYPES.GENERATED}
 58	          >
 59	            <span data-test-id={PARAMETER_VALUE_TYPES.GENERATED}>
 60	              {t('Generated (expression)')}
 61	            </span>
 62	          </SelectOption>
 63	          <SelectOption
 64	            description={t('Default value for this parameter')}
 65	            value={PARAMETER_VALUE_TYPES.VALUE}
 66	          >
 67	            <span data-test-id={PARAMETER_VALUE_TYPES.VALUE}>{t('Value')}</span>
 68	          </SelectOption>
 69	          <SelectOption description={t('No default value')} value={PARAMETER_VALUE_TYPES.NONE}>
 70	            <span data-test-id={PARAMETER_VALUE_TYPES.NONE}>{t('None')}</span>
 71	          </SelectOption>
 72	        </FormPFSelect>
 73	      </FormGroup>
 74	      {valueType === PARAMETER_VALUE_TYPES.VALUE && (
 75	        <FormGroup
 76	          className="form-group-indented"
 77	          fieldId={`${parameter.name}-value`}
 78	          label={t('Value')}
 79	        >
 80	          <TextInput
 81	            id={`${parameter.name}-value`}
 82	            isDisabled={isEditDisabled}
 83	            onChange={(_event, value) => onChange({ ...parameter, value })}
 84	            value={parameter.value}
 85	          />
 86	        </FormGroup>
 87	      )}
 88	      {valueType === PARAMETER_VALUE_TYPES.GENERATED && (
 89	        <FormGroup
 90	          className="form-group-indented"
 91	          fieldId={`${parameter.name}-generated`}
 92	          label={t('From')}
 93	        >
 94	          <TextInput
 95	            id={`${parameter.name}-generated`}
 96	            isDisabled={isEditDisabled}
 97	            onChange={(_event, expression) => onChange({ ...parameter, from: expression })}
 98	            value={parameter.from}
 99	          />
100	        </FormGroup>
101	      )}
102	    </>
103	  );
104	};
105	
106	export default SelectParameterValueType;

